window.SECAI = window.SECAI || {}; SECAI.questions = SECAI.questions || [];
SECAI.questions.push(
  { id:"D4-001", domain:4, obj:"4.1", diff:"easy", q:"A mid-size bank wants one team to own AI standards, review projects, curate platforms, and maintain the AI policy across all departments. Which governance structure best fits this need?", options:["An incident response retainer","A bug bounty program","An AI Center of Excellence (CoE)","A data warehouse team"], answer:2, explain:"An <strong>AI Center of Excellence (CoE)</strong> is a cross-functional hub that defines standards, reviews projects, curates tools, and maintains AI policy across the organization.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An incident response retainer</b>: handles breach response, not ongoing AI standards and project review.</span><span class='qd'><b>A bug bounty program</b>: crowdsources vulnerability reports and does not own AI governance.</span><span class='qd'><b>A data warehouse team</b>: manages stored data, not AI policy, reviews, or platform curation.</span>" },
  { id:"D4-002", domain:4, obj:"4.1", diff:"medium", q:"A small firm in a highly regulated industry wants the fastest path to standardized AI practices and centralized control. Which AI CoE positioning model is most appropriate?", options:["A federated model","A hybrid model","No CoE at all","A centralized model"], answer:3, explain:"A <strong>centralized model</strong> places most AI development and all governance in one team, speeding standardization and suiting smaller or highly regulated organizations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A federated model</b>: distributes developers into business units, which slows standardization.</span><span class='qd'><b>A hybrid model</b>: balances control and efficiency but is not the fastest route to full standardization for a small firm.</span><span class='qd'><b>No CoE at all</b>: leaves the firm without the centralized control it explicitly wants.</span>" },
  { id:"D4-003", domain:4, obj:"4.1", diff:"medium", q:"A large enterprise wants business units to build AI within set boundaries while a central team owns platforms, policies, and reviews. Which model does this describe?", options:["A centralized model","A federated model","A shadow model","A hybrid model"], answer:3, explain:"A <strong>hybrid model</strong> centralizes platforms, policies, and reviews while letting business units develop within predefined boundaries, and it is the most common choice.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A centralized model</b>: puts nearly all development in one team, not in the business units.</span><span class='qd'><b>A federated model</b>: makes the CoE only a standards and assurance function without centralized platforms.</span><span class='qd'><b>A shadow model</b>: is not a governance positioning model; shadow AI refers to unsanctioned tools.</span>" },
  { id:"D4-004", domain:4, obj:"4.1", diff:"easy", q:"An AI governance document states what is allowed, what evidence is needed for audits, and who is authorized to make decisions. What is this document called?", options:["A model card","A pipeline diagram","An AI policy","A retention schedule"], answer:2, explain:"An <strong>AI policy</strong> states what is allowed, what audit evidence is required, and who is authorized to make decisions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A model card</b>: documents one system's purpose and limitations, not organization-wide authorization rules.</span><span class='qd'><b>A pipeline diagram</b>: shows data flow, not permitted uses or decision authority.</span><span class='qd'><b>A retention schedule</b>: defines how long data is kept, not what AI use is allowed.</span>" },
  { id:"D4-005", domain:4, obj:"4.1", diff:"medium", q:"A team needs to convert the AI policy into predictable, auditable actions specifying who does what, when, and with what evidence across the lifecycle. What are they creating?", options:["An AI policy","AI procedures","A risk appetite statement","A marketing brief"], answer:1, explain:"<strong>AI procedures</strong> convert policy into predictable, auditable actions, specifying who does what, when, and with what evidence across the AI lifecycle.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An AI policy</b>: states what is allowed at a high level but does not specify step-by-step execution.</span><span class='qd'><b>A risk appetite statement</b>: expresses tolerance for risk, not procedural steps.</span><span class='qd'><b>A marketing brief</b>: describes promotion plans, not lifecycle controls.</span>" },
  { id:"D4-006", domain:4, obj:"4.1", diff:"hard", q:"Which controls enforce AI governance in day-to-day operations through capabilities like model and prompt registries with versioning, least-privilege access, secrets management, and prompt or response filtering?", options:["Technical guardrails","Marketing guidelines","Board resolutions","Quarterly surveys"], answer:0, explain:"<strong>Technical guardrails</strong> are controls that enforce governance in daily operations, including registries with versioning, least-privilege access, secrets management, and prompt or response filtering.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Marketing guidelines</b>: shape messaging, not technical enforcement of governance.</span><span class='qd'><b>Board resolutions</b>: set high-level direction but do not enforce controls in operations.</span><span class='qd'><b>Quarterly surveys</b>: gather feedback and do not enforce least privilege or filtering.</span>" },
  { id:"D4-007", domain:4, obj:"4.1", diff:"easy", q:"Which AI role builds and maintains the pipelines that acquire, clean, label, and deliver data with quality controls?", options:["The AI auditor","The platform engineer","The AI risk analyst","The data engineer"], answer:3, explain:"The <strong>data engineer</strong> builds and maintains the pipelines that acquire, clean, label, and deliver data with appropriate quality controls.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI auditor</b>: provides independent assurance, not data pipeline construction.</span><span class='qd'><b>The platform engineer</b>: provides shared infrastructure, not the data pipelines themselves.</span><span class='qd'><b>The AI risk analyst</b>: assesses use-case risk, not data engineering.</span>" },
  { id:"D4-008", domain:4, obj:"4.1", diff:"medium", q:"Which role takes model prototypes and turns them into production-grade models by optimizing code, packaging dependencies, and writing inference services?", options:["The data scientist","The AI governance engineer","The AI auditor","The machine learning engineer"], answer:3, explain:"The <strong>machine learning engineer</strong> transforms prototypes into production-grade models by optimizing code, packaging dependencies, writing inference services, and designing evaluation tests.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data scientist</b>: explores data and builds baseline models but does not productionize them.</span><span class='qd'><b>The AI governance engineer</b>: codifies approval workflows, not model optimization.</span><span class='qd'><b>The AI auditor</b>: independently verifies controls, not model engineering.</span>" },
  { id:"D4-009", domain:4, obj:"4.1", diff:"medium", q:"Which role automates the model lifecycle on the platform, managing versioning and lineage, orchestrating retraining, and setting up drift monitoring and rollbacks?", options:["The data engineer","The AI architect","The AI risk analyst","The MLOps engineer"], answer:3, explain:"The <strong>MLOps engineer</strong> automates the lifecycle on the platform, managing versioning and lineage, orchestrating retraining, and setting up monitoring to detect drift and trigger rollbacks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data engineer</b>: handles data pipelines, not lifecycle automation and rollbacks.</span><span class='qd'><b>The AI architect</b>: designs how components fit together but does not automate the pipeline.</span><span class='qd'><b>The AI risk analyst</b>: assesses risk rather than orchestrating retraining.</span>" },
  { id:"D4-010", domain:4, obj:"4.1", diff:"hard", q:"Which role designs measures to protect data, models, and prompts from threats such as leakage, poisoning, prompt injection, and abuse?", options:["The data scientist","The platform engineer","The AI security architect","The AI auditor"], answer:2, explain:"The <strong>AI security architect</strong> designs safeguards like secrets management, access control, isolation, content filtering, and adversarial testing to protect against leakage, poisoning, prompt injection, and abuse.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data scientist</b>: defines problems and baseline models, not security safeguards.</span><span class='qd'><b>The platform engineer</b>: provides infrastructure, not threat-specific protections.</span><span class='qd'><b>The AI auditor</b>: independently verifies controls rather than designing them.</span>" },
  { id:"D4-011", domain:4, obj:"4.1", diff:"hard", q:"Which role integrates policy into daily operations by codifying approval workflows, automatically collecting required evidence, and enforcing retention and audit requirements through the platform?", options:["The AI security architect","The machine learning engineer","The data engineer","The AI governance engineer"], answer:3, explain:"The <strong>AI governance engineer</strong> integrates policy into operations by codifying approval workflows, auto-collecting evidence, and enforcing retention and audit requirements through the platform.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI security architect</b>: focuses on protecting against threats, not approval workflow codification.</span><span class='qd'><b>The machine learning engineer</b>: builds production models, not governance workflows.</span><span class='qd'><b>The data engineer</b>: builds data pipelines, not policy enforcement workflows.</span>" },
  { id:"D4-012", domain:4, obj:"4.1", diff:"medium", q:"Which role assesses use cases on legal, ethical, and business criteria, recommends mitigations, and tracks indicators like override rates and error impacts?", options:["The AI auditor","The AI risk analyst","The platform engineer","The data scientist"], answer:1, explain:"The <strong>AI risk analyst</strong> assesses use cases on legal, ethical, and business criteria, recommends mitigations, and tracks indicators such as override rates and error impacts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI auditor</b>: provides independent assurance after the fact, not ongoing risk assessment and mitigation design.</span><span class='qd'><b>The platform engineer</b>: builds infrastructure, not risk assessments.</span><span class='qd'><b>The data scientist</b>: develops models, not legal and ethical risk evaluation.</span>" },
  { id:"D4-013", domain:4, obj:"4.1", diff:"hard", q:"Which role provides independent assurance by sampling artifacts and logs, recreating decisions, verifying approvals follow policy, and confirming monitoring operates as documented?", options:["The AI auditor","The AI governance engineer","The AI risk analyst","The MLOps engineer"], answer:0, explain:"The <strong>AI auditor</strong> provides independent assurance by sampling artifacts and logs, recreating decisions, verifying approvals, and confirming monitoring works as documented.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI governance engineer</b>: builds and enforces workflows but is not independent of them.</span><span class='qd'><b>The AI risk analyst</b>: assesses and recommends but does not provide independent assurance.</span><span class='qd'><b>The MLOps engineer</b>: automates the lifecycle, not independent verification.</span>" },
  { id:"D4-014", domain:4, obj:"4.1", diff:"easy", q:"Which role outlines how AI components fit together within the enterprise, choosing patterns for data flows, model serving, and integration with existing systems?", options:["The data engineer","The AI architect","The AI auditor","The AI risk analyst"], answer:1, explain:"The <strong>AI architect</strong> outlines how components fit together within the enterprise, choosing patterns for data flows, model serving, and integration to keep solutions scalable, resilient, and cost-effective.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data engineer</b>: builds data pipelines, not the overall architecture.</span><span class='qd'><b>The AI auditor</b>: verifies controls rather than designing system architecture.</span><span class='qd'><b>The AI risk analyst</b>: evaluates risk, not architecture patterns.</span>" },
  { id:"D4-015", domain:4, obj:"4.1", diff:"medium", q:"Which role provides the shared infrastructure teams use to experiment and deploy safely, including compute clusters, storage, feature stores, model registries, and observability tools?", options:["The machine learning engineer","The data scientist","The platform engineer","The AI auditor"], answer:2, explain:"The <strong>platform engineer</strong> provides shared infrastructure such as compute clusters, storage, feature stores, model registries, and observability tools.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The machine learning engineer</b>: builds production models on the platform, not the platform itself.</span><span class='qd'><b>The data scientist</b>: explores data and builds baseline models.</span><span class='qd'><b>The AI auditor</b>: independently verifies controls, not infrastructure provisioning.</span>" },
  { id:"D4-016", domain:4, obj:"4.1", diff:"medium", q:"An AI policy refers to a 'model registry.' According to good policy practice, what should that term be defined as?", options:["A marketing list of AI product names","A folder of meeting notes","A controlled inventory tracking every model and prompt template with version, training data sources, owners, approvals, and monitoring status","A public press release archive"], answer:2, explain:"A <strong>controlled inventory tracking every model and prompt template with version, training data sources, owners, approvals, and monitoring status</strong> is what a model registry should mean, and policy should define it in plain language.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A marketing list of AI product names</b>: is promotional and tracks none of the governance metadata.</span><span class='qd'><b>A folder of meeting notes</b>: lacks versioning, owners, and approval tracking.</span><span class='qd'><b>A public press release archive</b>: is external communication, not a model inventory.</span>" },
  { id:"D4-017", domain:4, obj:"4.1", diff:"hard", q:"Which kinds of decisions should an AI policy explicitly require formal sign-off for?", options:["Choosing the office coffee vendor","Scheduling routine team standups","Moving a model from testing into production, using customer data for training, or enabling autonomous actions","Renaming a Slack channel"], answer:2, explain:"An AI policy should require formal sign-off for high-stakes decisions such as <strong>moving a model from testing into production, using customer data for training, or enabling autonomous actions</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Choosing the office coffee vendor</b>: is unrelated to AI risk and needs no AI sign-off.</span><span class='qd'><b>Scheduling routine team standups</b>: is operational housekeeping, not an AI risk decision.</span><span class='qd'><b>Renaming a Slack channel</b>: has no governance impact on AI systems.</span>" },
  { id:"D4-018", domain:4, obj:"4.1", diff:"easy", q:"What does a well-functioning AI CoE provide so that all AI initiatives align with business goals like innovation and efficiency?", options:["A ban on all external partnerships","A guarantee that no model will ever fail","A unified vision that prevents fragmented projects","Unlimited compute with no oversight"], answer:2, explain:"A CoE provides a <strong>unified vision that prevents fragmented projects</strong>, ensuring initiatives support business goals and resources are used efficiently.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A ban on all external partnerships</b>: contradicts the CoE's role in fostering external collaboration.</span><span class='qd'><b>A guarantee that no model will ever fail</b>: no governance structure can promise zero failures.</span><span class='qd'><b>Unlimited compute with no oversight</b>: opposes the CoE's purpose of standards and control.</span>" },
  { id:"D4-019", domain:4, obj:"4.1", diff:"medium", q:"Beyond standards and reviews, which additional function does an AI CoE often serve to address the need for specialized expertise?", options:["A payroll processing center","A talent development hub that trains employees and attracts AI experts","A physical security guard service","A customer billing department"], answer:1, explain:"An AI CoE often acts as a <strong>talent development hub that trains employees and attracts AI experts</strong>, building a skilled workforce.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A payroll processing center</b>: is an HR finance function unrelated to AI expertise.</span><span class='qd'><b>A physical security guard service</b>: protects facilities, not AI talent development.</span><span class='qd'><b>A customer billing department</b>: handles invoicing, not AI skill building.</span>" },
  { id:"D4-020", domain:4, obj:"4.1", diff:"medium", q:"In a typical AI deployment handoff, who establishes trustworthy datasets and a clear problem statement at the start?", options:["The AI auditor and AI risk analyst","The board of directors","The data engineer and data scientist","The marketing team"], answer:2, explain:"A typical handoff begins with the <strong>data engineer and data scientist</strong> establishing trustworthy datasets and a clear problem statement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI auditor and AI risk analyst</b>: verify controls after go-live, not at dataset creation.</span><span class='qd'><b>The board of directors</b>: sets direction but does not build datasets.</span><span class='qd'><b>The marketing team</b>: promotes products, not data and problem definition.</span>" },
  { id:"D4-021", domain:4, obj:"4.1", diff:"hard", q:"An organization is early in its AI GRC maturity journey. Which combination of actions best reflects an early-stage program?", options:["Seek independent third-party validation for all high-risk systems","Publish a concise policy and inventory existing AI uses","Fully automate evidence collection across the enterprise","Refine advanced risk-management practices with mature tooling"], answer:1, explain:"Early-stage AI GRC programs typically <strong>publish a concise policy and inventory existing AI uses</strong>; registries, standards, automation, and third-party validation come later.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Seek independent third-party validation for all high-risk systems</b>: is a later-stage maturity activity.</span><span class='qd'><b>Fully automate evidence collection across the enterprise</b>: occurs in later refinement stages.</span><span class='qd'><b>Refine advanced risk-management practices with mature tooling</b>: is a sign of an advanced, not early, program.</span>" },
  { id:"D4-022", domain:4, obj:"4.1", diff:"easy", q:"What is the primary purpose of effective AI governance as a management system?", options:["To eliminate the need for any human staff","To decide whether, how, and under what controls AI is designed, built, acquired, deployed, and monitored","To maximize model size regardless of cost","To replace all existing security tools"], answer:1, explain:"Effective AI governance is a management system that helps decide <strong>whether, how, and under what controls AI is designed, built, acquired, deployed, and monitored</strong>, combining people, policy, process, and technical guardrails.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To eliminate the need for any human staff</b>: governance relies on people, not their removal.</span><span class='qd'><b>To maximize model size regardless of cost</b>: contradicts responsible resource use.</span><span class='qd'><b>To replace all existing security tools</b>: governance complements, not replaces, security controls.</span>" },
  { id:"D4-023", domain:4, obj:"4.1", diff:"medium", q:"Why do well-written AI procedures help reduce 'shadow AI'?", options:["By blocking all internet access company-wide","By embedding documentation and approvals into each step, creating a reliable record of accountability","By deleting all model logs automatically","By outsourcing every AI decision to vendors"], answer:1, explain:"Well-written procedures <strong>embed documentation and approvals into each step, creating a reliable record of accountability</strong>, which reduces shadow AI and builds leadership confidence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>By blocking all internet access company-wide</b>: is overbroad and not how procedures reduce shadow AI.</span><span class='qd'><b>By deleting all model logs automatically</b>: would destroy the audit trail procedures rely on.</span><span class='qd'><b>By outsourcing every AI decision to vendors</b>: shifts accountability away rather than recording it.</span>" },
  { id:"D4-024", domain:4, obj:"4.1", diff:"medium", q:"A federated AI CoE model is chosen. Where do AI developers primarily sit and what does the CoE do?", options:["Developers and all governance sit only in the CoE","Developers are eliminated entirely","Developers sit in business units; the CoE is a standards and assurance function","The CoE only handles payroll"], answer:2, explain:"In a federated model, <strong>developers sit in business units while the CoE is a standards and assurance function</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Developers and all governance sit only in the CoE</b>: describes the centralized, not federated, model.</span><span class='qd'><b>Developers are eliminated entirely</b>: federation distributes developers, it does not remove them.</span><span class='qd'><b>The CoE only handles payroll</b>: misstates the CoE's standards and assurance role.</span>" },
  { id:"D4-025", domain:4, obj:"4.1", diff:"easy", q:"Which disciplines should an effective AI CoE blend together?", options:["AI engineering, data science, security, privacy, legal, compliance, risk, procurement, IT operations, and product","Only software developers","Only the legal department","Only external consultants"], answer:0, explain:"An effective CoE blends <strong>AI engineering, data science, security, privacy, legal, compliance, risk, procurement, IT operations, and product</strong> management.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only software developers</b>: omits the cross-functional disciplines a CoE requires.</span><span class='qd'><b>Only the legal department</b>: cannot cover engineering, data, and operations needs.</span><span class='qd'><b>Only external consultants</b>: a CoE is an internal cross-functional team.</span>" },
  { id:"D4-026", domain:4, obj:"4.1", diff:"hard", q:"An organization wants its AI policy to be enforceable and actually read. Which property best supports this?", options:["It is hundreds of pages of legal jargon","It is kept secret from employees","It is short enough to read in one sitting and clear enough to support enforcement","It changes wording daily without versioning"], answer:2, explain:"An AI policy should be <strong>short enough to read in one sitting and clear enough to support enforcement</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is hundreds of pages of legal jargon</b>: discourages reading and weakens enforceability.</span><span class='qd'><b>It is kept secret from employees</b>: a policy must be known to be followed.</span><span class='qd'><b>It changes wording daily without versioning</b>: creates confusion and undermines enforcement.</span>" },
  { id:"D4-027", domain:4, obj:"4.1", diff:"medium", q:"When an AI policy references 'high-risk AI,' what should it do for clarity?", options:["Define it, for example as systems influencing credit, employment, health, safety, or core security","Leave it undefined to allow flexibility","Refer readers to an external paywalled site","Use only the vendor's marketing term"], answer:0, explain:"The policy should <strong>define high-risk AI, for example as systems influencing credit, employment, health, safety, or core security functions</strong>, using plain-language definitions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Leave it undefined to allow flexibility</b>: creates confusion and weakens enforcement.</span><span class='qd'><b>Refer readers to an external paywalled site</b>: makes the definition inaccessible.</span><span class='qd'><b>Use only the vendor's marketing term</b>: marketing language is not a precise risk definition.</span>" },
  { id:"D4-028", domain:4, obj:"4.1", diff:"easy", q:"What is the main benefit of a CoE fostering external collaboration with industry partners, academia, and vendors?", options:["Avoiding any internal documentation","Staying at the forefront of AI advancements and enhancing competitiveness through shared knowledge","Eliminating the need for a policy","Removing all human oversight"], answer:1, explain:"External collaboration helps the organization <strong>stay at the forefront of AI advancements and enhance competitiveness through shared knowledge and innovation</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Avoiding any internal documentation</b>: collaboration does not replace documentation.</span><span class='qd'><b>Eliminating the need for a policy</b>: external partners do not remove the need for internal policy.</span><span class='qd'><b>Removing all human oversight</b>: collaboration does not eliminate oversight requirements.</span>" },
  { id:"D4-029", domain:4, obj:"4.1", diff:"medium", q:"Which statement best describes how a hybrid CoE model balances competing goals?", options:["It removes all central control for maximum speed","It forbids business units from any development","It centralizes platforms, policies, and reviews while allowing units to develop within boundaries, balancing control and efficiency","It eliminates reviews to reduce paperwork"], answer:2, explain:"The hybrid model <strong>centralizes platforms, policies, and reviews while allowing units to develop within boundaries, balancing control and efficiency</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It removes all central control for maximum speed</b>: that abandons governance, not balances it.</span><span class='qd'><b>It forbids business units from any development</b>: that describes a centralized model.</span><span class='qd'><b>It eliminates reviews to reduce paperwork</b>: reviews remain central to the hybrid model.</span>" },
  { id:"D4-030", domain:4, obj:"4.1", diff:"hard", q:"A CoE is described as a 'coordination hub.' What benefit does that role deliver?", options:["Auditing only the finance ledger","Streamlining cross-departmental AI projects, minimizing duplication, and aligning resources","Manufacturing physical hardware","Replacing the HR department"], answer:1, explain:"As a coordination hub, the CoE <strong>streamlines cross-departmental AI projects, minimizes duplication, and aligns resources</strong>, boosting efficiency and accelerating deployment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Auditing only the finance ledger</b>: is a finance task unrelated to AI coordination.</span><span class='qd'><b>Manufacturing physical hardware</b>: is not a CoE coordination function.</span><span class='qd'><b>Replacing the HR department</b>: the CoE coordinates AI work, not HR operations.</span>" },
  { id:"D4-031", domain:4, obj:"4.1", diff:"medium", q:"Plain-language, role-based AI procedures let teams move quickly while still maintaining control over which areas?", options:["Office furniture purchasing","Data protection, security, fairness, and regulatory requirements","Cafeteria menus","Parking assignments"], answer:1, explain:"Well-written procedures let teams move quickly while maintaining control over <strong>data protection, security, fairness, and regulatory requirements</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Office furniture purchasing</b>: is unrelated to AI procedural control.</span><span class='qd'><b>Cafeteria menus</b>: have no bearing on AI governance.</span><span class='qd'><b>Parking assignments</b>: are administrative, not AI control areas.</span>" },
  { id:"D4-032", domain:4, obj:"4.1", diff:"easy", q:"Which combination does AI governance bring together so AI systems stay lawful, secure, reliable, and aligned with business objectives?", options:["Only firewalls and antivirus","People, policy, and process with technical guardrails","Only a single AI engineer","Only quarterly board meetings"], answer:1, explain:"AI governance combines <strong>people, policy, and process with technical guardrails</strong> so AI stays lawful, secure, reliable, and aligned with business objectives.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only firewalls and antivirus</b>: are narrow technical tools, not full governance.</span><span class='qd'><b>Only a single AI engineer</b>: cannot supply policy, process, and oversight alone.</span><span class='qd'><b>Only quarterly board meetings</b>: provide oversight cadence but not the full system.</span>" },
  { id:"D4-033", domain:4, obj:"4.1", diff:"medium", q:"An organization without a CoE keeps launching duplicate, misaligned AI projects across departments. Establishing a CoE most directly addresses this by providing what?", options:["More marketing spend","Faster internet connectivity","Larger office space","A unified vision and coordination that align initiatives and reduce duplication"], answer:3, explain:"A CoE provides a <strong>unified vision and coordination that align initiatives and reduce duplication</strong>, preventing fragmented projects.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>More marketing spend</b>: does not align AI projects or reduce duplication.</span><span class='qd'><b>Faster internet connectivity</b>: is infrastructure, not governance alignment.</span><span class='qd'><b>Larger office space</b>: does not address fragmented AI initiatives.</span>" },
  { id:"D4-034", domain:4, obj:"4.1", diff:"hard", q:"An auditor needs to trace which version of a model was in production last quarter, its training data sources, and who approved it. Which governance artifact is designed to answer this?", options:["The cafeteria schedule","The brand style guide","The travel policy","The model registry"], answer:3, explain:"The <strong>model registry</strong> is a controlled inventory tracking each model and prompt template with version, training data sources, owners, approvals, and monitoring status.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The cafeteria schedule</b>: contains no model lineage information.</span><span class='qd'><b>The brand style guide</b>: governs visual identity, not model versions.</span><span class='qd'><b>The travel policy</b>: covers expenses, not AI model tracking.</span>" },
  { id:"D4-035", domain:4, obj:"4.2", diff:"easy", q:"A lending model trained mostly on data from one region rejects qualified applicants from another region. Which AI risk does this illustrate?", options:["A denial-of-service attack","A licensing dispute","Algorithmic bias and unfair outcomes","A hardware failure"], answer:2, explain:"This illustrates <strong>algorithmic bias and unfair outcomes</strong>, where training data reflecting historical or regional imbalance produces unfair treatment of groups.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A denial-of-service attack</b>: targets availability, not fairness of decisions.</span><span class='qd'><b>A licensing dispute</b>: concerns intellectual property, not biased outputs.</span><span class='qd'><b>A hardware failure</b>: is an infrastructure issue, not a data-driven bias problem.</span>" },
  { id:"D4-036", domain:4, obj:"4.2", diff:"medium", q:"Which responsible AI principle requires that outcomes not disadvantage individuals based on protected or irrelevant characteristics?", options:["Sustainability","Latency","Fairness","Throughput"], answer:2, explain:"<strong>Fairness</strong> means outcomes should not disadvantage individuals based on protected or irrelevant characteristics, which involves testing for disparities across groups.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sustainability</b>: concerns energy and resource use, not protected-characteristic fairness.</span><span class='qd'><b>Latency</b>: is a performance metric, not a fairness principle.</span><span class='qd'><b>Throughput</b>: measures processing volume, not equitable outcomes.</span>" },
  { id:"D4-037", domain:4, obj:"4.2", diff:"medium", q:"Which responsible AI principle ensures it is clear who is responsible for an AI system's decisions, preventing the excuse that 'the model did it'?", options:["Sustainability","Inclusiveness","Latency","Accountability"], answer:3, explain:"<strong>Accountability</strong> defines who is responsible for decisions and the systems supporting them, preventing the 'the model did it' excuse.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sustainability</b>: addresses resource and energy impact, not responsibility for decisions.</span><span class='qd'><b>Inclusiveness</b>: ensures equitable service across populations, not ownership of decisions.</span><span class='qd'><b>Latency</b>: is a performance characteristic, not an accountability principle.</span>" },
  { id:"D4-038", domain:4, obj:"4.2", diff:"medium", q:"A medical diagnosis assistant needs more detailed reasoning than a movie recommender. Which principle governs how well stakeholders can understand a system's output?", options:["Throughput","Transparency and explainability","Data minimization","Rate limiting"], answer:1, explain:"<strong>Transparency and explainability</strong> concern how well stakeholders can understand a system's reasoning, with the appropriate level scaling to the risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Throughput</b>: measures volume processed, not understandability.</span><span class='qd'><b>Data minimization</b>: limits collected data, not output explanation.</span><span class='qd'><b>Rate limiting</b>: throttles requests, not reasoning transparency.</span>" },
  { id:"D4-039", domain:4, obj:"4.2", diff:"hard", q:"An AI system makes proposals, but a person makes the final decision on every case. Which oversight model is this?", options:["Human-on-the-loop","Fully autonomous","Human-out-of-the-loop","Human-in-the-loop"], answer:3, explain:"<strong>Human-in-the-loop</strong> means the AI makes proposals but a person makes the final decision.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Human-on-the-loop</b>: lets AI decide routine cases while humans monitor and can override.</span><span class='qd'><b>Fully autonomous</b>: removes human decision-making, which the scenario does not.</span><span class='qd'><b>Human-out-of-the-loop</b>: is not the described model; a person is clearly deciding here.</span>" },
  { id:"D4-040", domain:4, obj:"4.2", diff:"hard", q:"An AI handles routine cases automatically while humans monitor and can override when needed. Which oversight model is this?", options:["Human-on-the-loop","Human-in-the-loop","Fully manual","No oversight"], answer:0, explain:"<strong>Human-on-the-loop</strong> means AI decides routine cases while humans monitor behavior and have authority to override.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Human-in-the-loop</b>: requires a human to make the final decision on each case.</span><span class='qd'><b>Fully manual</b>: would mean no AI decisions at all.</span><span class='qd'><b>No oversight</b>: contradicts the described human monitoring and override.</span>" },
  { id:"D4-041", domain:4, obj:"4.2", diff:"easy", q:"Training data includes PII that was not meant to be there, and the problem appears only after PII shows up in outputs. Which AI risk is this?", options:["Sustainability cost","Vendor lock-in","Slow inference","Accidental data leakage and privacy exposure"], answer:3, explain:"This is <strong>accidental data leakage and privacy exposure</strong>, where sensitive data is inadvertently captured, stored, or surfaced in outputs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sustainability cost</b>: concerns energy use, not privacy exposure.</span><span class='qd'><b>Vendor lock-in</b>: is a procurement concern, not data leakage.</span><span class='qd'><b>Slow inference</b>: is a performance issue, not a privacy risk.</span>" },
  { id:"D4-042", domain:4, obj:"4.2", diff:"medium", q:"A demand forecasting model becomes less accurate after a new competitor enters the market. Which AI risk does this describe?", options:["Prompt injection","Watermarking failure","Distribution shift and model drift","License expiration"], answer:2, explain:"<strong>Distribution shift and model drift</strong> occur when changes in the world create a mismatch between production data and the data the model was trained on.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Prompt injection</b>: manipulates model instructions, not market-driven accuracy loss.</span><span class='qd'><b>Watermarking failure</b>: relates to content provenance, not drift.</span><span class='qd'><b>License expiration</b>: is a contractual issue, not a data distribution change.</span>" },
  { id:"D4-043", domain:4, obj:"4.2", diff:"hard", q:"An attacker modifies training data to push a model toward a behavior they choose. Which threat is this?", options:["Hallucination","Model card omission","Latency spike","Data poisoning"], answer:3, explain:"<strong>Data poisoning</strong> involves modifying training data to push a model toward attacker-chosen behavior.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hallucination</b>: is the model producing plausible but false output, not data tampering.</span><span class='qd'><b>Model card omission</b>: is missing documentation, not an attack on training data.</span><span class='qd'><b>Latency spike</b>: is a performance event, not a poisoning attack.</span>" },
  { id:"D4-044", domain:4, obj:"4.2", diff:"hard", q:"An attacker tries to determine whether a specific person's record was part of a model's training set. Which privacy attack is this?", options:["Membership inference","Prompt injection","Demographic parity","Rate limiting"], answer:0, explain:"<strong>Membership inference</strong> aims to detect whether specific records were part of the training set, posing a privacy risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Prompt injection</b>: manipulates LLM instructions, not training-set membership.</span><span class='qd'><b>Demographic parity</b>: is a fairness metric, not an attack.</span><span class='qd'><b>Rate limiting</b>: is a defensive control, not a privacy attack.</span>" },
  { id:"D4-045", domain:4, obj:"4.2", diff:"medium", q:"A model generates a plausible but factually incorrect statement. What is this called, and which technique helps mitigate it?", options:["A hallucination, mitigated by retrieval-augmented generation that cites documents","A poisoning attack, mitigated by faster GPUs","Drift, mitigated by larger fonts","Bias, mitigated by deleting logs"], answer:0, explain:"This is a <strong>hallucination, mitigated by retrieval-augmented generation that cites documents</strong>, along with source grounding and output verification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A poisoning attack, mitigated by faster GPUs</b>: misnames the issue and the fix.</span><span class='qd'><b>Drift, mitigated by larger fonts</b>: drift is a distribution change, and fonts are irrelevant.</span><span class='qd'><b>Bias, mitigated by deleting logs</b>: bias is unfairness, and deleting logs removes evidence.</span>" },
  { id:"D4-046", domain:4, obj:"4.2", diff:"medium", q:"A support agent allowed to process refunds is manipulated by crafted prompts into issuing unauthorized credits. Which risk category does this fall under?", options:["Sustainability and social impact","Intellectual property leakage","Risks from autonomy and real-world action","Energy inefficiency"], answer:2, explain:"This falls under <strong>risks from autonomy and real-world action</strong>, where an acting AI can be exploited or cause unintended effects.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sustainability and social impact</b>: concerns resource use, not unauthorized actions.</span><span class='qd'><b>Intellectual property leakage</b>: involves protected content, not refund manipulation.</span><span class='qd'><b>Energy inefficiency</b>: is a resource concern, not an autonomy exploit.</span>" },
  { id:"D4-047", domain:4, obj:"4.2", diff:"hard", q:"To safely grant an AI agent the ability to take actions, which safeguard set is most appropriate?", options:["Least-privilege scope, granular approvals, rate limits, reversible changes, and human validation for high-impact actions","Unlimited permissions with no logging","Disabling all monitoring to reduce cost","Allowing the agent to bypass authentication"], answer:0, explain:"Safe autonomy requires <strong>least-privilege scope, granular approvals, rate limits, reversible changes, and human validation for high-impact actions</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Unlimited permissions with no logging</b>: removes the very controls that make autonomy safe.</span><span class='qd'><b>Disabling all monitoring to reduce cost</b>: eliminates visibility into agent behavior.</span><span class='qd'><b>Allowing the agent to bypass authentication</b>: treats the model as trusted, which it should not be.</span>" },
  { id:"D4-048", domain:4, obj:"4.2", diff:"medium", q:"When an AI interacts with other systems through tools or APIs, how should security engineers treat the model?", options:["As a fully trusted administrator","As exempt from access controls","As a physical network device","As an untrusted client, enforcing authentication, authorization, and input validation"], answer:3, explain:"Engineers should treat the model <strong>as an untrusted client, enforcing authentication, authorization, and input validation</strong> just as for external users.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>As a fully trusted administrator</b>: grants excessive trust and invites abuse.</span><span class='qd'><b>As exempt from access controls</b>: removes essential safeguards.</span><span class='qd'><b>As a physical network device</b>: misclassifies the model and ignores its untrusted nature.</span>" },
  { id:"D4-049", domain:4, obj:"4.2", diff:"easy", q:"Which principle requires collecting and using data in a legitimate, minimal, and well-protected manner, managing consent and retention limits?", options:["Throughput optimization","Model compression","Marketing alignment","Privacy and data governance"], answer:3, explain:"<strong>Privacy and data governance</strong> ensures data is collected and used legitimately, minimally, and with strong protection, including consent and retention limits.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Throughput optimization</b>: improves speed, not privacy handling.</span><span class='qd'><b>Model compression</b>: reduces model size, not data governance.</span><span class='qd'><b>Marketing alignment</b>: concerns messaging, not lawful data use.</span>" },
  { id:"D4-050", domain:4, obj:"4.2", diff:"medium", q:"Which safety threat involves manipulating inputs so they appear normal to humans but cause a model to misclassify?", options:["Demographic parity","Model cards","Source grounding","Adversarial samples"], answer:3, explain:"<strong>Adversarial samples</strong> manipulate inputs to look normal to humans while causing misclassification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Demographic parity</b>: is a fairness metric, not an attack.</span><span class='qd'><b>Model cards</b>: are documentation artifacts, not attacks.</span><span class='qd'><b>Source grounding</b>: is a hallucination mitigation, not a threat.</span>" },
  { id:"D4-051", domain:4, obj:"4.2", diff:"hard", q:"Which attacks specifically aim to reconstruct training data or detect record membership, posing privacy risks?", options:["Model inversion and membership inference","Demographic parity and equal opportunity","Source grounding and RAG","Rate limiting and content filtering"], answer:0, explain:"<strong>Model inversion and membership inference</strong> aim to reconstruct or detect whether specific records were in the training set, creating privacy risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Demographic parity and equal opportunity</b>: are fairness metrics, not privacy attacks.</span><span class='qd'><b>Source grounding and RAG</b>: are hallucination mitigations, not attacks.</span><span class='qd'><b>Rate limiting and content filtering</b>: are defensive controls, not privacy attacks.</span>" },
  { id:"D4-052", domain:4, obj:"4.2", diff:"medium", q:"A fraud model trained mainly on weekday transactions flags weekend activity as suspicious. Which root cause does this represent?", options:["A prompt injection attack","Training data that omits important cases or reflects convenience sampling","An expired software license","A network outage"], answer:1, explain:"This represents <strong>training data that omits important cases or reflects convenience sampling</strong>, so the model reproduces gaps from the data it learned on.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A prompt injection attack</b>: targets LLM instructions, not weekday-only training data.</span><span class='qd'><b>An expired software license</b>: is a contractual issue, not a data coverage gap.</span><span class='qd'><b>A network outage</b>: is an availability problem, not a data representativeness issue.</span>" },
  { id:"D4-053", domain:4, obj:"4.2", diff:"easy", q:"Which fairness metrics are commonly used in bias audits to evaluate impartiality across demographic groups?", options:["Latency and throughput","Demographic parity and equal opportunity","Token count and context length","Uptime and MTTR"], answer:1, explain:"<strong>Demographic parity and equal opportunity</strong> are fairness metrics used in bias audits to evaluate equity across groups.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Latency and throughput</b>: are performance metrics, not fairness measures.</span><span class='qd'><b>Token count and context length</b>: describe model capacity, not fairness.</span><span class='qd'><b>Uptime and MTTR</b>: are availability metrics, not fairness metrics.</span>" },
  { id:"D4-054", domain:4, obj:"4.2", diff:"medium", q:"Why might a regulated organization choose a simpler, more interpretable model even when a complex one is highly accurate?", options:["Because simpler models always run faster","Because complex models can hide subtle discrimination or unintended logic that is hard to interpret","Because regulators forbid neural networks","Because accuracy never matters in regulated settings"], answer:1, explain:"Regulated organizations may prefer simpler models because <strong>complex models can hide subtle discrimination or unintended logic that is hard to interpret</strong>, and a simpler model may give comparable performance with more visibility.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because simpler models always run faster</b>: speed is not the stated reason and is not always true.</span><span class='qd'><b>Because regulators forbid neural networks</b>: no such blanket prohibition is described.</span><span class='qd'><b>Because accuracy never matters in regulated settings</b>: accuracy still matters; interpretability is the trade-off.</span>" },
  { id:"D4-055", domain:4, obj:"4.2", diff:"hard", q:"An organization relies on external model providers, open weights, and community datasets. Which governance practices best address the resulting provenance and versioning risk?", options:["Disabling all logging to save space","Letting models auto-update without notice","Supplier assessments, signed artifacts, and internal validation before major changes","Removing all access controls"], answer:2, explain:"Strong governance for third-party dependencies includes <strong>supplier assessments, signed artifacts, and internal validation before major changes</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disabling all logging to save space</b>: removes the audit trail needed to detect issues.</span><span class='qd'><b>Letting models auto-update without notice</b>: is exactly the provenance risk to avoid.</span><span class='qd'><b>Removing all access controls</b>: increases exposure rather than managing supplier risk.</span>" },
  { id:"D4-056", domain:4, obj:"4.2", diff:"medium", q:"Employees over-trust convincing AI outputs or under-trust them due to unfamiliarity. Which combination best balances these tendencies?", options:["Hiding all uncertainty from users","Training, interfaces that display uncertainty, and procedural secondary checks for high-impact actions","Forbidding any AI use entirely","Removing all human review"], answer:1, explain:"Balancing over- and under-trust calls for <strong>training, interfaces that display uncertainty, and procedural secondary checks for high-impact actions</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hiding all uncertainty from users</b>: encourages over-trust by concealing limitations.</span><span class='qd'><b>Forbidding any AI use entirely</b>: avoids the tool rather than calibrating trust.</span><span class='qd'><b>Removing all human review</b>: eliminates the secondary checks that calibrate trust.</span>" },
  { id:"D4-057", domain:4, obj:"4.2", diff:"easy", q:"What is the primary goal of safety and security as a responsible AI principle?", options:["To maximize energy consumption","To prevent harm caused by misuse or attacks","To increase marketing reach","To shorten model documentation"], answer:1, explain:"Safety and security aim <strong>to prevent harm caused by misuse or attacks</strong>, addressing adversarial inputs, poisoning, prompt injection, and insecure APIs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To maximize energy consumption</b>: is contrary to responsible resource use.</span><span class='qd'><b>To increase marketing reach</b>: is unrelated to preventing harm.</span><span class='qd'><b>To shorten model documentation</b>: documentation supports safety rather than being its goal.</span>" },
  { id:"D4-058", domain:4, obj:"4.2", diff:"medium", q:"Which technique helps mitigate the generation of toxic or unsafe content from a generative model?", options:["Policy filters that screen both prompts and outputs","Increasing the model's temperature","Removing all monitoring","Disabling authentication"], answer:0, explain:"<strong>Policy filters that screen both prompts and outputs</strong> help prevent toxic or unsafe content generation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increasing the model's temperature</b>: makes outputs more random, not safer.</span><span class='qd'><b>Removing all monitoring</b>: eliminates visibility into unsafe outputs.</span><span class='qd'><b>Disabling authentication</b>: weakens security and does not filter content.</span>" },
  { id:"D4-059", domain:4, obj:"4.2", diff:"hard", q:"A marketing team uses a generative model trained on unlicensed artwork and produces images resembling a living artist's portfolio. Which risk is this?", options:["Distribution shift","Membership inference","Intellectual property and content provenance risk","Sustainability cost"], answer:2, explain:"This is <strong>intellectual property and content provenance risk</strong>, where training on copyrighted material can lead to outputs that replicate protected content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Distribution shift</b>: concerns changing data over time, not IP infringement.</span><span class='qd'><b>Membership inference</b>: is a privacy attack, not an IP issue.</span><span class='qd'><b>Sustainability cost</b>: relates to energy use, not intellectual property.</span>" },
  { id:"D4-060", domain:4, obj:"4.2", diff:"medium", q:"Which controls help distinguish official AI outputs from unofficial ones and support content provenance?", options:["Watermarking and cryptographic signing","Higher inference temperature","Larger training batches","Disabling output filters"], answer:0, explain:"<strong>Watermarking and cryptographic signing</strong> are content provenance controls that help distinguish official from unofficial outputs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Higher inference temperature</b>: increases randomness, not provenance assurance.</span><span class='qd'><b>Larger training batches</b>: affect training, not output authenticity.</span><span class='qd'><b>Disabling output filters</b>: removes safeguards rather than adding provenance.</span>" },
  { id:"D4-061", domain:4, obj:"4.2", diff:"easy", q:"A customer-facing assistant confidently gives incorrect financial guidance. Even with no regulation broken, which risk is most directly raised?", options:["Reputational harm and loss of stakeholder trust","Improved sustainability","Lower latency","Stronger encryption"], answer:0, explain:"This raises <strong>reputational harm and loss of stakeholder trust</strong>, since inaccurate or inappropriate outputs can undermine trust even without breaking rules.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Improved sustainability</b>: is a benefit area, not a risk raised here.</span><span class='qd'><b>Lower latency</b>: is a performance metric, unrelated to trust harm.</span><span class='qd'><b>Stronger encryption</b>: is a security control, not the risk in question.</span>" },
  { id:"D4-062", domain:4, obj:"4.2", diff:"medium", q:"Which defenses best address prompt injection and data exfiltration threats against large language models?", options:["Increasing model size only","Removing all input validation","Publishing system prompts publicly","Rate limiting, content filtering, and separating untrusted content from system instructions"], answer:3, explain:"Defenses include <strong>rate limiting, content filtering, and careful separation between untrusted content and the model's system instructions</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increasing model size only</b>: does not address injection or exfiltration.</span><span class='qd'><b>Removing all input validation</b>: increases exposure to injection.</span><span class='qd'><b>Publishing system prompts publicly</b>: helps attackers craft injections.</span>" },
  { id:"D4-063", domain:4, obj:"4.2", diff:"hard", q:"Effective AI governance views AI as a 'socio-technical system.' What does this mean for where risks can arise?", options:["Risks arise only from the GPU hardware","Risks arise only from network latency","Risks arise from people, processes, and environments, not only data and models","Risks arise only from the user interface color scheme"], answer:2, explain:"Viewing AI as a socio-technical system means <strong>risks arise from people, processes, and environments, not only data and models</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risks arise only from the GPU hardware</b>: ignores people, process, and data sources.</span><span class='qd'><b>Risks arise only from network latency</b>: is far too narrow a view of AI risk.</span><span class='qd'><b>Risks arise only from the user interface color scheme</b>: trivializes the breadth of socio-technical risk.</span>" },
  { id:"D4-064", domain:4, obj:"4.2", diff:"medium", q:"An email classifier trained on last year's phishing struggles with new generative-text tactics and novel domains. Which risk does this exemplify?", options:["Intellectual property leakage","Model accuracy and performance drift","Demographic parity violation","Watermark removal"], answer:1, explain:"This exemplifies <strong>model accuracy and performance drift</strong>, where conditions change and the model deteriorates over time.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Intellectual property leakage</b>: concerns protected content, not phishing accuracy decline.</span><span class='qd'><b>Demographic parity violation</b>: is a fairness issue, not changing attack tactics.</span><span class='qd'><b>Watermark removal</b>: relates to provenance, not classifier accuracy.</span>" },
  { id:"D4-065", domain:4, obj:"4.2", diff:"easy", q:"Which principle examines resource use and broader effects, encouraging smaller fine-tuned models over a single very large general model when appropriate?", options:["Accountability","Prompt injection defense","Sustainability and social impact","Membership inference"], answer:2, explain:"<strong>Sustainability and social impact</strong> examines resource use and broader effects, favoring efficient alternatives like smaller fine-tuned models.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accountability</b>: assigns responsibility for decisions, not resource efficiency.</span><span class='qd'><b>Prompt injection defense</b>: is a security control, not a sustainability principle.</span><span class='qd'><b>Membership inference</b>: is a privacy attack, not a sustainability concern.</span>" },
  { id:"D4-066", domain:4, obj:"4.2", diff:"medium", q:"A concise document outlines an AI system's purpose, data sources, training period, known limitations, intended users, and prohibited uses. What is this called?", options:["A penetration test report","A purchase order","A model card or system profile","A press release"], answer:2, explain:"A <strong>model card or system profile</strong> documents the system's purpose, data sources, training period, limitations, intended users, and prohibited uses.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A penetration test report</b>: documents security testing findings, not system purpose and limits.</span><span class='qd'><b>A purchase order</b>: is a procurement document, not a model description.</span><span class='qd'><b>A press release</b>: is external communication, not internal documentation.</span>" },
  { id:"D4-067", domain:4, obj:"4.2", diff:"hard", q:"Before releasing an AI system, which testing combination best reflects responsible practice?", options:["Accuracy tests, fairness checks across groups, stress tests with unusual inputs, and red-teaming","Only a quick demo to executives","Only checking that the UI loads","Only confirming the vendor invoice is paid"], answer:0, explain:"Responsible pre-release testing includes <strong>accuracy tests, fairness checks across groups, stress tests with unusual inputs, and red-teaming</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only a quick demo to executives</b>: does not test fairness, robustness, or safety.</span><span class='qd'><b>Only checking that the UI loads</b>: ignores model behavior and risk.</span><span class='qd'><b>Only confirming the vendor invoice is paid</b>: is administrative, not a release test.</span>" },
  { id:"D4-068", domain:4, obj:"4.3", diff:"easy", q:"Which law establishes a risk-based framework with tiers including 'unacceptable-risk' (prohibited), 'high-risk,' and 'limited-risk' AI applications?", options:["The EU AI Act","The OECD AI Principles","ISO/IEC 22989","The NIST AI RMF"], answer:0, explain:"The <strong>EU AI Act</strong> establishes a risk-based framework with unacceptable-risk (prohibited), high-risk, and limited-risk tiers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The OECD AI Principles</b>: are non-binding values-based guidance, not a risk-tier law.</span><span class='qd'><b>ISO/IEC 22989</b>: defines AI terminology, not legal risk tiers.</span><span class='qd'><b>The NIST AI RMF</b>: is a voluntary framework, not a law with prohibited tiers.</span>" },
  { id:"D4-069", domain:4, obj:"4.3", diff:"medium", q:"Under the EU AI Act, what must 'limited-risk' AI systems do?", options:["Undergo full high-risk conformity assessment","Be prohibited outright","Be exempt from all obligations","Comply with transparency rules, such as informing users they are interacting with AI or labeling synthetic media"], answer:3, explain:"Limited-risk AI must <strong>comply with transparency rules, such as informing users they are interacting with AI or labeling synthetic media</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Undergo full high-risk conformity assessment</b>: applies to high-risk systems, not limited-risk.</span><span class='qd'><b>Be prohibited outright</b>: applies to unacceptable-risk practices.</span><span class='qd'><b>Be exempt from all obligations</b>: limited-risk still carries transparency duties.</span>" },
  { id:"D4-070", domain:4, obj:"4.3", diff:"hard", q:"Which standard specifies the requirements for an AI Management System (AIMS) and is designed to be certifiable through third-party assessment?", options:["ISO/IEC 22989:2022","ISO/IEC 5338:2023","OECD AI Principles","ISO/IEC 42001:2023"], answer:3, explain:"<strong>ISO/IEC 42001:2023</strong> specifies requirements for an AI Management System (AIMS) and is certifiable via third-party assessment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ISO/IEC 22989:2022</b>: defines AI concepts and terminology, not an AIMS.</span><span class='qd'><b>ISO/IEC 5338:2023</b>: outlines AI lifecycle processes, not management-system certification.</span><span class='qd'><b>OECD AI Principles</b>: are non-binding guidance, not a certifiable standard.</span>" },
  { id:"D4-071", domain:4, obj:"4.3", diff:"medium", q:"The NIST AI Risk Management Framework organizes AI risk management into which four functions?", options:["Plan, Do, Check, Act","Govern, Map, Measure, and Manage","Identify, Protect, Detect, Respond","Collect, Clean, Train, Deploy"], answer:1, explain:"The NIST AI RMF organizes risk management into <strong>Govern, Map, Measure, and Manage</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Plan, Do, Check, Act</b>: is a generic quality cycle, not the AI RMF functions.</span><span class='qd'><b>Identify, Protect, Detect, Respond</b>: are from the NIST Cybersecurity Framework, not the AI RMF.</span><span class='qd'><b>Collect, Clean, Train, Deploy</b>: describe a data pipeline, not the AI RMF functions.</span>" },
  { id:"D4-072", domain:4, obj:"4.3", diff:"easy", q:"Which framework is a voluntary set of practices, widely adopted beyond the U.S. for its practicality, organizing AI risk into four functions?", options:["The NIST AI RMF","The EU AI Act","GDPR","ISO/IEC 23894"], answer:0, explain:"The <strong>NIST AI RMF</strong> is a voluntary framework widely adopted beyond the U.S. for its practicality, organized into Govern, Map, Measure, and Manage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The EU AI Act</b>: is a binding law, not a voluntary framework.</span><span class='qd'><b>GDPR</b>: is a data protection regulation, not the four-function AI risk framework.</span><span class='qd'><b>ISO/IEC 23894</b>: provides AI risk-management guidance but is not the NIST four-function framework.</span>" },
  { id:"D4-073", domain:4, obj:"4.3", diff:"hard", q:"Which ISO/IEC standard provides guidance on AI-specific risk management, including integrating AI risks into enterprise risk programs and establishing risk criteria?", options:["ISO/IEC 42001:2023","ISO/IEC 23894:2023","ISO/IEC 22989:2022","ISO/IEC 5338:2023"], answer:1, explain:"<strong>ISO/IEC 23894:2023</strong> provides guidance on AI-specific risk management, complementing ISO 42001.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ISO/IEC 42001:2023</b>: specifies an AI Management System, not risk-management guidance specifically.</span><span class='qd'><b>ISO/IEC 22989:2022</b>: defines terminology, not risk-management practices.</span><span class='qd'><b>ISO/IEC 5338:2023</b>: covers lifecycle processes, not risk-management guidance.</span>" },
  { id:"D4-074", domain:4, obj:"4.3", diff:"medium", q:"Which ISO/IEC standard defines AI concepts and terminology to keep terms like 'model,' 'training data,' and 'bias' consistent?", options:["ISO/IEC 42001:2023","ISO/IEC 23894:2023","ISO/IEC 22989:2022","ISO/IEC 5338:2023"], answer:2, explain:"<strong>ISO/IEC 22989:2022</strong> defines AI concepts and terminology for consistency across teams.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ISO/IEC 42001:2023</b>: specifies a management system, not terminology.</span><span class='qd'><b>ISO/IEC 23894:2023</b>: covers risk management, not vocabulary.</span><span class='qd'><b>ISO/IEC 5338:2023</b>: outlines lifecycle processes, not terminology definitions.</span>" },
  { id:"D4-075", domain:4, obj:"4.3", diff:"hard", q:"Which ISO/IEC standard outlines AI system lifecycle processes and highlights concerns like concept drift and model decay?", options:["ISO/IEC 22989:2022","ISO/IEC 42001:2023","ISO/IEC 23894:2023","ISO/IEC 5338:2023"], answer:3, explain:"<strong>ISO/IEC 5338:2023</strong> outlines AI system lifecycle processes and highlights AI-specific concerns such as concept drift and model decay.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ISO/IEC 22989:2022</b>: defines terminology, not lifecycle processes.</span><span class='qd'><b>ISO/IEC 42001:2023</b>: specifies an AI Management System, not lifecycle process detail.</span><span class='qd'><b>ISO/IEC 23894:2023</b>: focuses on risk management, not the lifecycle.</span>" },
  { id:"D4-076", domain:4, obj:"4.3", diff:"easy", q:"Which intergovernmental, values-based guidance, first adopted in 2019 and updated in 2024, is not legally binding?", options:["The EU AI Act","ISO/IEC 42001","GDPR","The OECD AI Principles"], answer:3, explain:"The <strong>OECD AI Principles</strong> are non-binding, values-based intergovernmental guidance first adopted in 2019 and updated in 2024.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The EU AI Act</b>: is a binding law, not non-binding guidance.</span><span class='qd'><b>ISO/IEC 42001</b>: is a certifiable standard, not intergovernmental principles.</span><span class='qd'><b>GDPR</b>: is a binding regulation, not voluntary principles.</span>" },
  { id:"D4-077", domain:4, obj:"4.3", diff:"medium", q:"When did the EU AI Act come into effect, and when do most obligations take effect?", options:["It came into effect in 2019 with immediate full enforcement","It has not yet been enacted","It came into effect August 1, 2024, with most obligations from August 2, 2026","It applies only outside the EU"], answer:2, explain:"The EU AI Act <strong>came into effect August 1, 2024, with most obligations from August 2, 2026</strong>, though some dates differ.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It came into effect in 2019 with immediate full enforcement</b>: misstates both the date and the phased timeline.</span><span class='qd'><b>It has not yet been enacted</b>: it is already in effect.</span><span class='qd'><b>It applies only outside the EU</b>: it applies across EU Member States and to those selling into the EU market.</span>" },
  { id:"D4-078", domain:4, obj:"4.3", diff:"hard", q:"Why is achieving an ISO/IEC 42001 certification valuable for an AI vendor selling to enterprises?", options:["It guarantees the model will never produce errors","It exempts the vendor from all regulations","It removes the need for any internal policy","It allows third-party assessment to demonstrate responsible AI management, aiding vendor assurance and compliance"], answer:3, explain:"ISO/IEC 42001 certification <strong>allows third-party assessment to demonstrate responsible AI management, aiding vendor assurance and compliance</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees the model will never produce errors</b>: no certification guarantees error-free models.</span><span class='qd'><b>It exempts the vendor from all regulations</b>: certification does not override laws.</span><span class='qd'><b>It removes the need for any internal policy</b>: a management system requires internal policy, not its removal.</span>" },
  { id:"D4-079", domain:4, obj:"4.3", diff:"medium", q:"What is the twofold commercial impact of compliance described for AI?", options:["Noncompliance brings legal and reputational risk, while robust compliance can unlock new markets","Compliance only adds cost with no benefit","Compliance is irrelevant to sales","Compliance always blocks market access"], answer:0, explain:"Compliance is twofold: <strong>noncompliance brings legal and reputational risk, while robust compliance can unlock new markets</strong> and shorten procurement cycles.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Compliance only adds cost with no benefit</b>: ignores the market-access upside.</span><span class='qd'><b>Compliance is irrelevant to sales</b>: compliance can shorten procurement and build trust.</span><span class='qd'><b>Compliance always blocks market access</b>: robust compliance enables, not blocks, access.</span>" },
  { id:"D4-080", domain:4, obj:"4.3", diff:"easy", q:"Which independent reviews assess whether an organization's systems, processes, and models meet specific requirements, conducted by neither developer nor purchaser?", options:["Internal stand-up meetings","Third-party compliance evaluations","Marketing focus groups","Employee satisfaction surveys"], answer:1, explain:"<strong>Third-party compliance evaluations</strong> are independent reviews by an evaluator who is neither developer nor purchaser.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Internal stand-up meetings</b>: are team coordination, not independent evaluations.</span><span class='qd'><b>Marketing focus groups</b>: gauge customer opinion, not compliance.</span><span class='qd'><b>Employee satisfaction surveys</b>: measure morale, not system compliance.</span>" },
  { id:"D4-081", domain:4, obj:"4.3", diff:"medium", q:"How can a current SOC 2 Type II report, recent penetration test, and documented privacy assessment affect a SaaS vendor adding generative features?", options:["They eliminate the need for any security controls","They guarantee zero data breaches","They can shorten procurement cycles by reducing the buyer's need for duplicate testing","They make the product exempt from GDPR"], answer:2, explain:"Such evidence can <strong>shorten procurement cycles by reducing the buyer's need for duplicate testing</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They eliminate the need for any security controls</b>: evidence supplements controls, not replaces them.</span><span class='qd'><b>They guarantee zero data breaches</b>: no report can guarantee that.</span><span class='qd'><b>They make the product exempt from GDPR</b>: compliance evidence does not grant legal exemptions.</span>" },
  { id:"D4-082", domain:4, obj:"4.3", diff:"hard", q:"In regulated sectors like finance and healthcare, buyers may require evidence that AI models operate under which kind of program?", options:["A social media marketing program","A general office-supply procurement program","A holiday scheduling program","A model risk management program with validation, drift testing, and human-in-the-loop controls"], answer:3, explain:"Buyers may require evidence of a <strong>model risk management program with validation, drift testing, and human-in-the-loop controls</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A social media marketing program</b>: is unrelated to model risk assurance.</span><span class='qd'><b>A general office-supply procurement program</b>: does not address model risk.</span><span class='qd'><b>A holiday scheduling program</b>: is an HR task, not model governance.</span>" },
  { id:"D4-083", domain:4, obj:"4.3", diff:"medium", q:"How do third-party evaluations influence cyber insurance?", options:["They have no effect on insurance","Underwriters may request recent assessments; demonstrated maturity can yield better terms while gaps may raise premiums","They always void all coverage","They replace the need for any policy"], answer:1, explain:"Third-party evaluations influence insurance because <strong>underwriters may request recent assessments; demonstrated maturity can yield better terms while gaps may raise premiums</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They have no effect on insurance</b>: underwriters increasingly examine control maturity.</span><span class='qd'><b>They always void all coverage</b>: assessments do not automatically void coverage.</span><span class='qd'><b>They replace the need for any policy</b>: evaluations inform, not replace, insurance.</span>" },
  { id:"D4-084", domain:4, obj:"4.3", diff:"easy", q:"Which regulatory theme requires maintaining an up-to-date register of AI models and tools, detailing intended use, data, and whether they impact safety or rights?", options:["Maximize model size","Hide AI usage from regulators","Inventory AI use cases and classify risk","Eliminate documentation"], answer:2, explain:"<strong>Inventory AI use cases and classify risk</strong> requires an up-to-date register of models and tools with intended use, data, and safety or rights impact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Maximize model size</b>: is not a regulatory theme.</span><span class='qd'><b>Hide AI usage from regulators</b>: contradicts transparency expectations.</span><span class='qd'><b>Eliminate documentation</b>: opposes the inventory and classification requirement.</span>" },
  { id:"D4-085", domain:4, obj:"4.3", diff:"medium", q:"Which common regulatory theme calls for data minimization, purpose limitation, and meaningful human review when AI decisions significantly impact individuals?", options:["Design for lawful data use and human oversight","Maximize data collection","Remove all human review","Avoid recording any decisions"], answer:0, explain:"<strong>Design for lawful data use and human oversight</strong> calls for data minimization, purpose limitation, and meaningful human review with avenues to contest outcomes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Maximize data collection</b>: contradicts data minimization.</span><span class='qd'><b>Remove all human review</b>: opposes the human oversight requirement.</span><span class='qd'><b>Avoid recording any decisions</b>: contradicts accountability and traceability.</span>" },
  { id:"D4-086", domain:4, obj:"4.3", diff:"hard", q:"Which theme warns against overstating AI capabilities so disclosures are accurate and not viewed as deceptive?", options:["Inventory AI use cases","Manage third-party dependencies","Ensure claims match reality","Provide transparency and resource"], answer:2, explain:"<strong>Ensure claims match reality</strong> warns against overstating capabilities, since exaggerated claims may be deemed deceptive.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Inventory AI use cases</b>: concerns registering models, not accuracy of claims.</span><span class='qd'><b>Manage third-party dependencies</b>: addresses suppliers, not marketing claims.</span><span class='qd'><b>Provide transparency and resource</b>: focuses on user notices, not capability overstatement.</span>" },
  { id:"D4-087", domain:4, obj:"4.3", diff:"medium", q:"Which regulatory theme treats model providers, data brokers, and annotation vendors as regulated suppliers requiring documentation and security attestations?", options:["Ensure claims match reality","Manage third-party and open-source dependencies","Establish accountable governance","Provide transparency and resource"], answer:1, explain:"<strong>Manage third-party and open-source dependencies</strong> treats providers, brokers, and vendors as regulated suppliers requiring documentation, attestations, and bias-testing evidence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ensure claims match reality</b>: addresses accurate disclosures, not supplier management.</span><span class='qd'><b>Establish accountable governance</b>: concerns ownership of risk decisions, not vendor controls.</span><span class='qd'><b>Provide transparency and resource</b>: focuses on user notices, not supplier obligations.</span>" },
  { id:"D4-088", domain:4, obj:"4.3", diff:"easy", q:"Which theme requires offering clear user notices, publishing relevant model and data summaries for high-risk uses, and creating channels to contest outcomes?", options:["Provide transparency and resource","Maximize profit margins","Reduce all documentation","Hide model details"], answer:0, explain:"<strong>Provide transparency and resource</strong> requires user notices, published summaries for high-risk uses, and channels to correct or contest outcomes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Maximize profit margins</b>: is a business goal, not a transparency theme.</span><span class='qd'><b>Reduce all documentation</b>: contradicts publishing summaries.</span><span class='qd'><b>Hide model details</b>: opposes transparency requirements.</span>" },
  { id:"D4-089", domain:4, obj:"4.3", diff:"medium", q:"In an AI policy, what is the difference between sanctioned AI and unsanctioned (shadow) AI?", options:["Sanctioned AI is vetted and approved; shadow AI is adopted independently by employees without vetting","Sanctioned AI is always free; shadow AI always costs money","Sanctioned AI is illegal; shadow AI is legal","There is no meaningful difference"], answer:0, explain:"<strong>Sanctioned AI is vetted and approved; shadow AI is adopted independently by employees without vetting</strong>, such as free web interfaces or browser extensions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sanctioned AI is always free; shadow AI always costs money</b>: cost is not the distinguishing factor.</span><span class='qd'><b>Sanctioned AI is illegal; shadow AI is legal</b>: this reverses and misstates the relationship.</span><span class='qd'><b>There is no meaningful difference</b>: the difference in approval and vetting is central.</span>" },
  { id:"D4-090", domain:4, obj:"4.3", diff:"hard", q:"How do mature programs encourage employees to prefer sanctioned AI tools over shadow AI?", options:["By offering a searchable catalog of pre-approved AI assistants with single sign-on and clear guidance","By banning all AI and removing internet access","By ignoring the problem entirely","By punishing all AI users equally"], answer:0, explain:"Mature programs <strong>offer a searchable catalog of pre-approved AI assistants with single sign-on and clear guidance</strong>, creating safe, high-utility alternatives.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>By banning all AI and removing internet access</b>: is overbroad and pushes users toward workarounds.</span><span class='qd'><b>By ignoring the problem entirely</b>: does nothing to steer users to safe tools.</span><span class='qd'><b>By punishing all AI users equally</b>: discourages even sanctioned, approved use.</span>" },
  { id:"D4-091", domain:4, obj:"4.3", diff:"medium", q:"What is the key trade-off between public and private models in an AI policy?", options:["Private models are always free and public models always paid","Public models cannot process any data","Private models offer no data control","Public models offer speed and breadth but raise data-storage and training-use concerns; private models give more control with more engineering effort"], answer:3, explain:"The trade-off is that <strong>public models offer speed and breadth but raise data-storage and training-use concerns; private models give more control with more engineering effort</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Private models are always free and public models always paid</b>: cost is not the defining trade-off.</span><span class='qd'><b>Public models cannot process any data</b>: public models do process data; the concern is where it goes.</span><span class='qd'><b>Private models offer no data control</b>: private models offer greater control over data residency and keys.</span>" },
  { id:"D4-092", domain:4, obj:"4.3", diff:"hard", q:"For processing sensitive health or financial records, what should an AI policy prioritize?", options:["Private models with explicit data isolation, customer-managed keys, and no-training assurances","Free public chatbots with no guarantees","Models that retain all prompts for provider training","Tools with no encryption or contracts"], answer:0, explain:"For high-risk data, policy should prioritize <strong>private models with explicit data isolation, customer-managed keys, and no-training assurances</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Free public chatbots with no guarantees</b>: lack the isolation and assurances sensitive data needs.</span><span class='qd'><b>Models that retain all prompts for provider training</b>: risk exposing sensitive records.</span><span class='qd'><b>Tools with no encryption or contracts</b>: provide none of the required protections.</span>" },
  { id:"D4-093", domain:4, obj:"4.3", diff:"medium", q:"An AI policy should align with the organization's data classification scheme. What should those classifications dictate?", options:["AI handling rules, such as whether data can be used for training, RAG, or prompting and what masking applies","The color of the user interface","The vendor's stock price","The office seating chart"], answer:0, explain:"Classifications should dictate <strong>AI handling rules, such as whether data can be used for training, RAG, or prompting and what masking applies</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The color of the user interface</b>: is unrelated to data handling.</span><span class='qd'><b>The vendor's stock price</b>: has no bearing on classification-based rules.</span><span class='qd'><b>The office seating chart</b>: is administrative, not a data-handling rule.</span>" },
  { id:"D4-094", domain:4, obj:"4.3", diff:"easy", q:"When an organization lacks a mature data classification scheme, what simplified rule can an AI policy start with?", options:["Treat source code, credentials, customer PII, and unreleased product info as restricted until a full scheme exists","Treat all data as public by default","Allow all data into public models freely","Delete all data immediately"], answer:0, explain:"A simplified starting rule is to <strong>treat source code, credentials, customer PII, and unreleased product info as restricted until a full scheme exists</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Treat all data as public by default</b>: exposes sensitive data unnecessarily.</span><span class='qd'><b>Allow all data into public models freely</b>: ignores restricted-data protections.</span><span class='qd'><b>Delete all data immediately</b>: is impractical and unrelated to classification.</span>" },
  { id:"D4-095", domain:4, obj:"4.3", diff:"medium", q:"A common policy approach prohibits restricted data from leaving the trust boundary and requires automatic redaction for which classification before sending to a model?", options:["Public data","Press releases","Marketing brochures","Confidential data"], answer:3, explain:"A common approach requires <strong>automatic redaction for confidential data before it is sent to a model</strong>, while prohibiting restricted data from leaving the trust boundary.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Public data</b>: is already shareable and does not require redaction.</span><span class='qd'><b>Press releases</b>: are public communications, not confidential data needing redaction.</span><span class='qd'><b>Marketing brochures</b>: are public materials, not confidential data.</span>" },
  { id:"D4-096", domain:4, obj:"4.3", diff:"hard", q:"A privacy evaluator tracing personal data through an AI pipeline would most likely check for which items?", options:["Lawful basis, data minimization, retention schedules, and de-identification effectiveness","The CEO's calendar availability","The brand's social media follower count","The office Wi-Fi password strength"], answer:0, explain:"A privacy evaluator checks <strong>lawful basis, data minimization, retention schedules, and de-identification effectiveness</strong> as personal data flows through the pipeline.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The CEO's calendar availability</b>: is unrelated to data privacy review.</span><span class='qd'><b>The brand's social media follower count</b>: is a marketing metric, not a privacy control.</span><span class='qd'><b>The office Wi-Fi password strength</b>: is general security, not personal-data pipeline tracing.</span>" },
  { id:"D4-097", domain:4, obj:"4.3", diff:"medium", q:"Independent penetration testing of AI systems may specifically investigate which AI-relevant aspects?", options:["Prompt injection resilience, model-interface authentication, and logging that could capture sensitive prompts","The font choice in the documentation","The number of office printers","The vendor's holiday schedule"], answer:0, explain:"Independent testing may investigate <strong>prompt injection resilience, model-interface authentication, and logging that could capture sensitive prompts</strong>.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The font choice in the documentation</b>: is cosmetic, not a security concern.</span><span class='qd'><b>The number of office printers</b>: is unrelated to AI attack surface.</span><span class='qd'><b>The vendor's holiday schedule</b>: has no bearing on penetration testing.</span>" },
  { id:"D4-098", domain:4, obj:"4.3", diff:"hard", q:"For a classification model that prioritizes fraud investigations, what would independent model validation most likely confirm?", options:["That the model uses the largest possible neural network","That data splits prevent leakage and performance holds on previously unused samples","That marketing claims are doubled","That all logging is disabled"], answer:1, explain:"Independent validation would confirm <strong>that data splits prevent leakage and performance holds on previously unused samples</strong>, replicating training and testing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>That the model uses the largest possible neural network</b>: model size is not what validation confirms.</span><span class='qd'><b>That marketing claims are doubled</b>: validation checks reality, not inflated claims.</span><span class='qd'><b>That all logging is disabled</b>: validation supports evidence, not removing logs.</span>" },
  { id:"D4-099", domain:4, obj:"4.3", diff:"easy", q:"Which theme requires clearly defining who is responsible for AI risk decisions, including senior leadership oversight, and recording those decisions?", options:["Maximize automation","Establish accountable governance","Reduce all oversight","Avoid documentation"], answer:1, explain:"<strong>Establish accountable governance</strong> requires clearly defining responsibility for AI risk decisions, including senior leadership oversight, and recording them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Maximize automation</b>: is not the accountability theme.</span><span class='qd'><b>Reduce all oversight</b>: contradicts the call for leadership oversight.</span><span class='qd'><b>Avoid documentation</b>: opposes recording decisions for audit traceability.</span>" },
  { id:"D4-100", domain:4, obj:"4.3", diff:"medium", q:"Which theme calls for detailed assessments addressing data protection, model risk, security threats, fairness, and human factors before launching high-risk applications?", options:["Ensure claims match reality","Provide transparency and resource","Manage third-party dependencies","Conduct impact and risk assessments before launch"], answer:3, explain:"<strong>Conduct impact and risk assessments before launch</strong> calls for detailed assessments of data protection, model risk, security, fairness, accessibility, and human factors for high-risk applications.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ensure claims match reality</b>: addresses accurate disclosures, not pre-launch assessment.</span><span class='qd'><b>Provide transparency and resource</b>: focuses on user notices, not risk assessment.</span><span class='qd'><b>Manage third-party dependencies</b>: concerns suppliers, not impact assessment.</span>" }
);
